import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { MagnifyingGlassIcon, FunnelIcon, UserPlusIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';

const Politicians = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedParty, setSelectedParty] = useState('all');
  const [selectedDistrict, setSelectedDistrict] = useState('all');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const politicians = [
    {
      id: 1,
      name: 'Ranil Wickremesinghe',
      party: 'UNP',
      district: 'Colombo',
      position: 'President',
      promisesKept: 85,
      totalPromises: 120,
      image: 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Ranil_Wickremesinghe_2017.jpg/800px-Ranil_Wickremesinghe_2017.jpg',
      bio: 'Current President of Sri Lanka, leader of United National Party',
      achievements: ['Economic reforms', 'International diplomacy', 'Debt restructuring']
    },
    {
      id: 2,
      name: 'Sajith Premadasa',
      party: 'SJB',
      district: 'Colombo',
      position: 'Opposition Leader',
      promisesKept: 67,
      totalPromises: 95,
      image: 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Sajith_Premadasa_%28cropped%29.jpg/800px-Sajith_Premadasa_%28cropped%29.jpg',
      bio: 'Leader of Samagi Jana Balawegaya, former Minister of Housing',
      achievements: ['Housing development', 'Youth empowerment', 'Social welfare programs']
    },
    {
      id: 3,
      name: 'Anura Kumara Dissanayake',
      party: 'NPP',
      district: 'Colombo',
      position: 'Party Leader',
      promisesKept: 52,
      totalPromises: 78,
      image: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2c/Anura_Kumara_Dissanayake.jpg/800px-Anura_Kumara_Dissanayake.jpg',
      bio: 'Leader of National People\'s Power, Member of Parliament',
      achievements: ['Anti-corruption campaigns', 'Good governance advocacy']
    },
    {
      id: 4,
      name: 'Mahinda Rajapaksa',
      party: 'SLPP',
      district: 'Hambantota',
      position: 'Former President',
      promisesKept: 43,
      totalPromises: 68,
      image: 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7f/Mahinda_Rajapaksa_2018.jpg/800px-Mahinda_Rajapaksa_2018.jpg',
      bio: 'Former President of Sri Lanka, former Prime Minister',
      achievements: ['Ended civil war', 'Infrastructure development', 'Port city development']
    },
  ];

  const parties = ['all', 'UNP', 'SJB', 'NPP', 'SLPP'];
  const districts = ['all', 'Colombo', 'Hambantota', 'Kandy', 'Galle', 'Jaffna'];

  const filteredPoliticians = politicians.filter(politician => {
    const matchesSearch = politician.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesParty = selectedParty === 'all' || politician.party === selectedParty;
    const matchesDistrict = selectedDistrict === 'all' || politician.district === selectedDistrict;
    return matchesSearch && matchesParty && matchesDistrict;
  });

  const handleAddPolitician = (e) => {
    e.preventDefault();
    toast.success('Politician added successfully!');
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 relative z-10">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-gray-800 dark:text-white">Sri Lankan Politicians</h1>
          <p className="text-gray-600 dark:text-gray-400 mt-2">Browse and track political leaders across the nation</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-gradient-to-r from-sriLanka-orange to-sriLanka-maroon text-white px-4 py-2 rounded-lg hover:shadow-lg transition-all flex items-center space-x-2"
        >
          <UserPlusIcon className="w-5 h-5" />
          <span>Add Politician</span>
        </button>
      </div>

      {/* Filters */}
      <div className="bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm rounded-xl shadow-lg p-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Search */}
          <div className="relative">
            <MagnifyingGlassIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="Search politicians by name..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-sriLanka-orange focus:border-transparent bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
            />
          </div>

          {/* Party Filter */}
          <div className="relative">
            <FunnelIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <select
              value={selectedParty}
              onChange={(e) => setSelectedParty(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-sriLanka-orange focus:border-transparent bg-white dark:bg-gray-700 text-gray-900 dark:text-white appearance-none"
            >
              {parties.map(party => (
                <option key={party} value={party}>
                  {party === 'all' ? 'All Parties' : party}
                </option>
              ))}
            </select>
          </div>

          {/* District Filter */}
          <div className="relative">
            <FunnelIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <select
              value={selectedDistrict}
              onChange={(e) => setSelectedDistrict(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-sriLanka-orange focus:border-transparent bg-white dark:bg-gray-700 text-gray-900 dark:text-white appearance-none"
            >
              {districts.map(district => (
                <option key={district} value={district}>
                  {district === 'all' ? 'All Districts' : district}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Politicians Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredPoliticians.map((politician, idx) => (
          <motion.div
            key={politician.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: idx * 0.05 }}
            whileHover={{ y: -5 }}
            className="bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm rounded-xl shadow-lg overflow-hidden hover:shadow-2xl transition-all"
          >
            <div className="relative h-56 overflow-hidden">
              <img 
                src={politician.image} 
                alt={politician.name}
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.target.onerror = null;
                  e.target.src = `https://via.placeholder.com/400x300?text=${politician.name}`;
                }}
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
              <div className="absolute bottom-0 left-0 right-0 p-4">
                <h3 className="text-white text-xl font-bold">{politician.name}</h3>
                <p className="text-white text-sm opacity-90">{politician.position}</p>
              </div>
              <div className="absolute top-4 right-4">
                <span className="px-3 py-1 bg-sriLanka-orange text-white rounded-full text-sm font-medium">
                  {politician.party}
                </span>
              </div>
            </div>
            <div className="p-6">
              <div className="flex justify-between items-center mb-3">
                <span className="text-sm text-gray-500 dark:text-gray-400 flex items-center">
                  📍 {politician.district}
                </span>
                <span className="text-sm text-gray-500 dark:text-gray-400">
                  MP since 2000
                </span>
              </div>
              <p className="text-gray-600 dark:text-gray-300 text-sm mb-4">{politician.bio}</p>
              
              <div className="space-y-3">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-600 dark:text-gray-400">Promises Kept:</span>
                  <span className="font-semibold text-green-600 dark:text-green-400">
                    {politician.promisesKept}/{politician.totalPromises}
                  </span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                  <div 
                    className="bg-green-500 rounded-full h-2 transition-all" 
                    style={{ width: `${(politician.promisesKept / politician.totalPromises) * 100}%` }}
                  ></div>
                </div>
                
                <div className="flex flex-wrap gap-2 mt-3">
                  {politician.achievements.slice(0, 2).map((achievement, i) => (
                    <span key={i} className="text-xs px-2 py-1 bg-sriLanka-orange/10 text-sriLanka-orange rounded-full">
                      🏆 {achievement}
                    </span>
                  ))}
                </div>
                
                <button className="w-full mt-4 bg-gradient-to-r from-sriLanka-orange to-sriLanka-maroon text-white py-2 rounded-lg hover:shadow-lg transition-all">
                  View Full Profile
                </button>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Add Politician Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <motion.div 
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-md p-6"
          >
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white mb-4">Add New Politician</h2>
            <form onSubmit={handleAddPolitician}>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Name</label>
                  <input type="text" className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Party</label>
                  <select className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white" required>
                    <option>UNP</option>
                    <option>SJB</option>
                    <option>NPP</option>
                    <option>SLPP</option>
                    <option>ITAK</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">District</label>
                  <input type="text" className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Position</label>
                  <input type="text" className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white" required />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Bio</label>
                  <textarea rows="3" className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white" required></textarea>
                </div>
              </div>
              <div className="flex space-x-3 mt-6">
                <button type="submit" className="flex-1 bg-gradient-to-r from-sriLanka-orange to-sriLanka-maroon text-white py-2 rounded-lg hover:shadow-lg transition-all">
                  Add Politician
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 py-2 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition-all">
                  Cancel
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </div>
  );
};

export default Politicians;
